// Helper function to get API base URL
const getApiUrl = (endpoint) => {
  const baseUrl = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
    ? 'http://localhost:5001'
    : 'https://two026backend.onrender.com'
  return `${baseUrl}${endpoint}`
}

// Helper function to get auth token
const getAuthToken = () => {
  return localStorage.getItem('authToken')
}

// Helper function to make API requests
const apiRequest = async (url, options = {}) => {
  const token = getAuthToken()
  const defaultOptions = {
    headers: {
      'Content-Type': 'application/json',
      ...(token && { 'Authorization': `Bearer ${token}` })
    }
  }
  
  const response = await fetch(url, { ...defaultOptions, ...options })
  
  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}))
    throw new Error(errorData.message || `HTTP error! status: ${response.status}`)
  }
  
  return response.json()
}

// Stock Management API
export const stockAPI = {
  // Stock Items
  getAll: (filters = {}) => {
    const params = new URLSearchParams(filters)
    return apiRequest(getApiUrl(`/api/stock-management/items?${params}`))
  },
  
  create: (data) => apiRequest(getApiUrl('/api/stock-management/items'), {
    method: 'POST',
    body: JSON.stringify(data)
  }),
  
  update: (data) => apiRequest(getApiUrl('/api/stock-management/items'), {
    method: 'POST',
    body: JSON.stringify(data)
  }),
  
  delete: (id) => apiRequest(getApiUrl(`/api/stock-management/items/${id}`), {
    method: 'DELETE'
  }),
  
  // Stock Statistics
  getStats: () => apiRequest(getApiUrl('/api/stock-management/stats')),
  
  // Stock Categories
  getCategories: () => apiRequest(getApiUrl('/api/stock-management/categories')),
  
  createCategory: (data) => apiRequest(getApiUrl('/api/stock-management/categories'), {
    method: 'POST',
    body: JSON.stringify(data)
  }),
  
  updateCategory: (data) => apiRequest(getApiUrl('/api/stock-management/categories'), {
    method: 'POST',
    body: JSON.stringify(data)
  }),
  
  deleteCategory: (id) => apiRequest(getApiUrl(`/api/stock-management/categories/${id}`), {
    method: 'DELETE'
  }),
  
  // Stock Subcategories
  getSubcategories: (categoryId) => {
    const params = categoryId ? `?categoryId=${categoryId}` : ''
    return apiRequest(getApiUrl(`/api/stock-management/subcategories${params}`))
  },
  
  createSubcategory: (categoryId, data) => apiRequest(getApiUrl('/api/stock-management/subcategories'), {
    method: 'POST',
    body: JSON.stringify({ categoryId, subcategoryData: data })
  }),
  
  deleteSubcategory: (categoryId, subcategoryId) => apiRequest(
    getApiUrl(`/api/stock-management/subcategories/${categoryId}/${subcategoryId}`), {
      method: 'DELETE'
    }
  )
}

// General Categories API (for Categories, Expense, Services tabs)
export const generalCategoriesAPI = {
  // Get categories by type
  getByType: (type) => {
    const params = type ? `?type=${type}` : ''
    return apiRequest(getApiUrl(`/api/general-categories${params}`))
  },
  
  // Get general categories (main Categories tab)
  getGeneral: () => apiRequest(getApiUrl('/api/general-categories/general')),
  
  // Get expense categories
  getExpense: () => apiRequest(getApiUrl('/api/general-categories/expense')),
  
  // Get service categories
  getService: () => apiRequest(getApiUrl('/api/general-categories/service')),
  
  // Create or update category
  saveCategory: (data) => apiRequest(getApiUrl('/api/general-categories'), {
    method: 'POST',
    body: JSON.stringify(data)
  }),
  
  // Delete category
  deleteCategory: (id) => apiRequest(getApiUrl(`/api/general-categories/${id}`), {
    method: 'DELETE'
  }),
  
  // Get subcategories
  getSubcategories: (categoryId, type) => {
    const params = new URLSearchParams()
    if (categoryId) params.append('categoryId', categoryId)
    if (type) params.append('type', type)
    return apiRequest(getApiUrl(`/api/general-categories/subcategories?${params}`))
  },
  
  // Create or update subcategory
  saveSubcategory: (categoryId, data) => apiRequest(getApiUrl('/api/general-categories/subcategories'), {
    method: 'POST',
    body: JSON.stringify({ categoryId, subcategoryData: data })
  }),
  
  // Delete subcategory
  deleteSubcategory: (categoryId, subcategoryId) => apiRequest(
    getApiUrl(`/api/general-categories/subcategories/${categoryId}/${subcategoryId}`), {
      method: 'DELETE'
    }
  )
}

