import React, { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { 
  Plus, Edit2, Trash2, Save, X, Search, MessageSquare, MessageCircle, 
  FileText, CheckCircle, Clock, AlertCircle, Send, Copy
} from 'lucide-react'

const MessageTemplates = () => {
  const [templates, setTemplates] = useState([])
  const [showAddForm, setShowAddForm] = useState(false)
  const [editingTemplate, setEditingTemplate] = useState(null)
  const [searchTerm, setSearchTerm] = useState('')
  const [selectedType, setSelectedType] = useState('all')
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [showPreview, setShowPreview] = useState(false)
  const [previewTemplate, setPreviewTemplate] = useState(null)
  
  const [formData, setFormData] = useState({
    templateName: '',
    templateType: 'welcome',
    subject: '',
    message: '',
    variables: ['{customerName}', '{serviceName}', '{reminderDate}', '{dueDate}'],
    isActive: true
  })

  // Template types
  const templateTypes = [
    { value: 'welcome', label: 'welcome Message', color: 'blue', icon: CheckCircle },
    { value: 'pending', label: 'Services Pending', color: 'yellow', icon: Clock },
    { value: 'completed', label: 'Services Completed', color: 'green', icon: CheckCircle },
    { value: 'reminder', label: 'General Reminder', color: 'purple', icon: AlertCircle },
    { value: 'followup', label: 'Follow Up', color: 'orange', icon: MessageCircle }
  ]

  // Default templates
  const defaultTemplates = {
    welcome: {
      templateName: 'Welcome Message',
      templateType: 'welcome',
      subject: 'Welcome to Our Service!',
      message: 'Hi {customerName},\n\nWelcome to our service! We are excited to have you with us. Your {serviceName} has been registered and we\'ll be in touch soon.\n\nBest regards,\nYour Service Team'
    },
    pending: {
      templateName: 'Service Pending Reminder',
      templateType: 'pending',
      subject: 'Service Pending - Action Required',
      message: 'Hi {customerName},\n\nThis is a reminder that your {serviceName} is pending. Please visit us or contact us to complete the process.\n\nReminder Date: {reminderDate}\n\nThank you!'
    },
    completed: {
      templateName: 'Service Completed',
      templateType: 'completed',
      subject: 'Service Completed Successfully',
      message: 'Hi {customerName},\n\nGreat news! Your {serviceName} has been completed successfully. Thank you for choosing our service.\n\nCompleted on: {reminderDate}\n\nWe appreciate your business!'
    },
    reminder: {
      templateName: 'General Reminder',
      templateType: 'reminder',
      subject: 'Reminder for Your Service',
      message: 'Hi {customerName},\n\nThis is a reminder for your {serviceName} scheduled on {reminderDate}. Please make sure to attend.\n\nThank you!'
    },
    followup: {
      templateName: 'Follow Up Message',
      templateType: 'followup',
      subject: 'Follow Up - Your Service',
      message: 'Hi {customerName},\n\nFollowing up on your {serviceName}. How is everything going? If you need any assistance, please let us know.\n\nBest regards!'
    }
  }

  useEffect(() => {
    fetchTemplates()
  }, [])

  const fetchTemplates = async () => {
    try {
      setLoading(true)
      // For now, use localStorage for templates (can be moved to backend later)
      const storedTemplates = JSON.parse(localStorage.getItem('messageTemplates') || '[]')
      
      // If no templates exist, create default ones
      if (storedTemplates.length === 0) {
        const defaultTemplatesArray = Object.values(defaultTemplates).map(template => ({
          ...template,
          _id: Date.now() + Math.random(),
          createdAt: new Date().toISOString(),
          isActive: true
        }))
        localStorage.setItem('messageTemplates', JSON.stringify(defaultTemplatesArray))
        setTemplates(defaultTemplatesArray)
      } else {
        setTemplates(storedTemplates)
      }
    } catch (error) {
      toast.error('Failed to fetch message templates')
      console.error('Error fetching templates:', error)
    } finally {
      setLoading(false)
    }
  }

  const saveTemplate = async () => {
    try {
      const templates = JSON.parse(localStorage.getItem('messageTemplates') || '[]')
      
      if (editingTemplate) {
        // Update existing template
        const updatedTemplates = templates.map(t => 
          t._id === editingTemplate._id 
            ? { ...formData, updatedAt: new Date().toISOString() }
            : t
        )
        localStorage.setItem('messageTemplates', JSON.stringify(updatedTemplates))
        toast.success('Template updated successfully!')
      } else {
        // Add new template
        const newTemplate = {
          ...formData,
          _id: Date.now().toString(),
          createdAt: new Date().toISOString()
        }
        templates.push(newTemplate)
        localStorage.setItem('messageTemplates', JSON.stringify(templates))
        toast.success('Template added successfully!')
      }
      
      setShowAddForm(false)
      setEditingTemplate(null)
      fetchTemplates()
    } catch (error) {
      toast.error('Failed to save template')
      console.error('Error saving template:', error)
    }
  }

  const deleteTemplate = async (templateId) => {
    if (!confirm('Are you sure you want to delete this template?')) {
      return
    }

    try {
      const templates = JSON.parse(localStorage.getItem('messageTemplates') || '[]')
      const updatedTemplates = templates.filter(t => t._id !== templateId)
      localStorage.setItem('messageTemplates', JSON.stringify(updatedTemplates))
      toast.success('Template deleted successfully!')
      fetchTemplates()
    } catch (error) {
      toast.error('Failed to delete template')
      console.error('Error deleting template:', error)
    }
  }

  const handleEdit = (template) => {
    setEditingTemplate(template)
    setFormData({
      templateName: template.templateName,
      templateType: template.templateType,
      subject: template.subject,
      message: template.message,
      variables: template.variables || ['{customerName}', '{serviceName}', '{reminderDate}', '{dueDate}'],
      isActive: template.isActive !== undefined ? template.isActive : true
    })
    setShowAddForm(true)
  }

  const handlePreview = (template) => {
    setPreviewTemplate(template)
    setShowPreview(true)
  }

  const resetForm = () => {
    setFormData({
      templateName: '',
      templateType: 'welcome',
      subject: '',
      message: '',
      variables: ['{customerName}', '{serviceName}', '{reminderDate}', '{dueDate}'],
      isActive: true
    })
    setEditingTemplate(null)
  }

  const loadDefaultTemplate = (type) => {
    const defaultTemplate = defaultTemplates[type]
    if (defaultTemplate) {
      setFormData({
        ...defaultTemplate,
        variables: defaultTemplate.variables || ['{customerName}', '{serviceName}', '{reminderDate}', '{dueDate}'],
        isActive: true
      })
    }
  }

  const filteredTemplates = templates.filter(template => {
    const matchesSearch = template.templateName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         template.subject?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         template.message?.toLowerCase().includes(searchTerm.toLowerCase())
    const matchesType = selectedType === 'all' || template.templateType === selectedType
    return matchesSearch && matchesType
  })

  const getTypeColor = (type) => {
    const typeConfig = templateTypes.find(t => t.value === type)
    return typeConfig ? typeConfig.color : 'gray'
  }

  const getTypeLabel = (type) => {
    const typeConfig = templateTypes.find(t => t.value === type)
    return typeConfig ? typeConfig.label : type
  }

  return (
    <div className="p-6">
      {/* Header */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 mb-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Message Templates</h1>
            <p className="text-gray-600 mt-1">Create and manage message templates for SMS and WhatsApp</p>
          </div>
          <button
            onClick={() => {
              resetForm()
              setShowAddForm(true)
            }}
            className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors flex items-center"
          >
            <Plus className="h-5 w-5 mr-2" />
            Add Template
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 mb-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Search Templates</label>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input
                type="text"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Search by name, subject, or message..."
                className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Filter by Type</label>
            <select
              value={selectedType}
              onChange={(e) => setSelectedType(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="all">All Types</option>
              {templateTypes.map(type => (
                <option key={type.value} value={type.value}>{type.label}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Templates List */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200">
        <div className="p-4">
          {loading ? (
            <div className="text-center py-8">
              <div className="text-gray-500">Loading templates...</div>
            </div>
          ) : filteredTemplates.length === 0 ? (
            <div className="text-center py-8">
              <FileText className="h-12 w-12 text-gray-400 mx-auto mb-4" />
              <div className="text-gray-500">No templates found</div>
              <button
                onClick={() => {
                  resetForm()
                  setShowAddForm(true)
                }}
                className="mt-4 text-blue-600 hover:text-blue-800"
              >
                Create your first template
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredTemplates.map((template) => {
                const TypeIcon = templateTypes.find(t => t.value === template.templateType)?.icon || FileText
                return (
                  <div key={template._id} className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow">
                    <div className="flex items-start justify-between mb-3">
                      <div className="flex items-center">
                        <div className={`p-2 rounded-lg bg-${getTypeColor(template.templateType)}-100`}>
                          <TypeIcon className={`h-5 w-5 text-${getTypeColor(template.templateType)}-600`} />
                        </div>
                        <div className="ml-3">
                          <h3 className="font-semibold text-gray-900">{template.templateName}</h3>
                          <span className={`inline-flex px-2 py-1 text-xs font-medium rounded-full bg-${getTypeColor(template.templateType)}-100 text-${getTypeColor(template.templateType)}-800`}>
                            {getTypeLabel(template.templateType)}
                          </span>
                        </div>
                      </div>
                      <div className="flex items-center space-x-1">
                        <button
                          onClick={() => handlePreview(template)}
                          className="text-gray-400 hover:text-gray-600 p-1"
                          title="Preview Template"
                        >
                          <FileText className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => handleEdit(template)}
                          className="text-blue-400 hover:text-blue-600 p-1"
                          title="Edit Template"
                        >
                          <Edit2 className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => deleteTemplate(template._id)}
                          className="text-red-400 hover:text-red-600 p-1"
                          title="Delete Template"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </div>
                    <div className="mb-3">
                      <div className="text-sm font-medium text-gray-700 mb-1">Subject:</div>
                      <div className="text-sm text-gray-600 truncate">{template.subject}</div>
                    </div>
                    <div className="mb-3">
                      <div className="text-sm font-medium text-gray-700 mb-1">Message Preview:</div>
                      <div className="text-sm text-gray-600 line-clamp-3">{template.message}</div>
                    </div>
                    <div className="flex items-center justify-between">
                      <div className="text-xs text-gray-500">
                        {template.isActive ? 'Active' : 'Inactive'}
                      </div>
                      <div className="flex items-center space-x-2">
                        <button
                          onClick={() => {
                            navigator.clipboard.writeText(template.message)
                            toast.success('Message copied to clipboard!')
                          }}
                          className="text-gray-400 hover:text-gray-600 p-1"
                          title="Copy Message"
                        >
                          <Copy className="h-4 w-4" />
                        </button>
                      </div>
                    </div>
                  </div>
                )
              })}
            </div>
          )}
        </div>
      </div>

      {/* Add/Edit Template Modal */}
      {showAddForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-2xl w-full mx-4 max-h-[90vh] overflow-y-auto">
            <div className="bg-blue-600 text-white px-6 py-4 rounded-t-lg">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold">
                  {editingTemplate ? 'Edit Template' : 'Add New Template'}
                </h3>
                <button
                  onClick={() => {
                    setShowAddForm(false)
                    resetForm()
                  }}
                  className="text-white hover:text-gray-200 transition-colors"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>
            </div>
            
            <div className="p-6">
              <form onSubmit={(e) => {
                e.preventDefault()
                saveTemplate()
              }} className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Template Name
                    </label>
                    <input
                      type="text"
                      value={formData.templateName}
                      onChange={(e) => setFormData({...formData, templateName: e.target.value})}
                      placeholder="Enter template name"
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Template Type
                    </label>
                    <div className="flex space-x-2">
                      <select
                        value={formData.templateType}
                        onChange={(e) => {
                          const newType = e.target.value
                          setFormData({...formData, templateType: newType})
                          loadDefaultTemplate(newType)
                        }}
                        className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      >
                        {templateTypes.map(type => (
                          <option key={type.value} value={type.value}>{type.label}</option>
                        ))}
                      </select>
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Subject
                  </label>
                  <input
                    type="text"
                    value={formData.subject}
                    onChange={(e) => setFormData({...formData, subject: e.target.value})}
                    placeholder="Enter message subject"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Message
                  </label>
                  <textarea
                    value={formData.message}
                    onChange={(e) => setFormData({...formData, message: e.target.value})}
                    placeholder="Enter your message here. Use variables like {customerName}, {serviceName}, {reminderDate}"
                    rows={6}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    required
                  />
                  <div className="mt-2 text-xs text-gray-500">
                    Available variables: {formData.variables.join(', ')}
                  </div>
                </div>

                <div className="flex items-center">
                  <input
                    type="checkbox"
                    id="isActive"
                    checked={formData.isActive}
                    onChange={(e) => setFormData({...formData, isActive: e.target.checked})}
                    className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
                  />
                  <label htmlFor="isActive" className="ml-2 text-sm text-gray-700">
                    Template is active
                  </label>
                </div>

                <div className="flex justify-end space-x-3 pt-4">
                  <button
                    type="button"
                    onClick={() => {
                      setShowAddForm(false)
                      resetForm()
                    }}
                    className="px-4 py-2 text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors flex items-center"
                  >
                    <Save className="h-4 w-4 mr-2" />
                    {editingTemplate ? 'Update Template' : 'Save Template'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Preview Modal */}
      {showPreview && previewTemplate && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-lg w-full mx-4">
            <div className="bg-gray-100 px-6 py-4 rounded-t-lg">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold">Template Preview</h3>
                <button
                  onClick={() => setShowPreview(false)}
                  className="text-gray-600 hover:text-gray-800 transition-colors"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>
            </div>
            
            <div className="p-6">
              <div className="mb-4">
                <div className="text-sm font-medium text-gray-700 mb-1">Template:</div>
                <div className="font-semibold text-gray-900">{previewTemplate.templateName}</div>
              </div>
              <div className="mb-4">
                <div className="text-sm font-medium text-gray-700 mb-1">Subject:</div>
                <div className="text-gray-900">{previewTemplate.subject}</div>
              </div>
              <div className="mb-4">
                <div className="text-sm font-medium text-gray-700 mb-1">Message:</div>
                <div className="bg-gray-50 p-3 rounded-lg text-gray-900 whitespace-pre-line">
                  {previewTemplate.message}
                </div>
              </div>
              <div className="flex justify-end space-x-3">
                <button
                  onClick={() => {
                    navigator.clipboard.writeText(previewTemplate.message)
                    toast.success('Message copied to clipboard!')
                  }}
                  className="px-4 py-2 text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors flex items-center"
                >
                  <Copy className="h-4 w-4 mr-2" />
                  Copy Message
                </button>
                <button
                  onClick={() => setShowPreview(false)}
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                >
                  Close
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default MessageTemplates
